```python
def fill_matrix(n, m):
    matrix = []
    for _ in range(n):
        row = list(map(int, input().split()))
        matrix.append(row)

    # Заполняем матрицу
    for i in range(1, n):
        for j in range(1, m):
            if matrix[i][j] == 0:
                matrix[i][j] = matrix[i-1][j] + matrix[i][j-1]

    return matrix

n, m = map(int, input().split())
matrix = fill_matrix(n, m)

# Выводим заполненную матрицу
for row in matrix:
    print(' '.join(map(str, row)))
```

