### commands.py
```python
from pyrogram import filters
from pyrogram.enums import ChatAction

def start_handler(client, message):
    if not message.from_user.id in client.users:
        client.users[message.from_user.id] = {"site": None}
    client.send_message(message.chat.id, "Привет! Я помогу тебе с пингами.")

def set_handler(client, message):
    site = message.text.split()[1:]
    if len(site) > 0:
        client.users[message.from_user.id]["site"] = site[0]
        client.send_message(message.chat.id, f"Адрес сайта успешно установлен: {site[0]}")
    else:
        client.send_message(message.chat.id, "Укажите адрес сайта.")

def list_handler(client, message):
    user_id = message.from_user.id
    if user_id in client.users and "results" in client.users[user_id]:
        results = client.users[user_id]["results"]
        for i, (result, date) in enumerate(reversed(results)):
            if i < 5:
                client.send_message(message.chat.id, f"{i+1}. Пинг: {result}, Дата: {date}")
            else:
                break
    else:
        client.send_message(message.chat.id, "Похоже, у вас нет результатов.")
```

### ping_manager.py
```python
from pyrogram import filters
from datetime import datetime
import time

class PingManager:
    def __init__(self):
        self.users = {}
        self.results = {}

    async def run(self):
        while True:
            await asyncio.sleep(60)
            for user_id in list(self.users.keys()):
                site = self.users.get(user_id).get("site")
                if site:
                    result = self.ping_site(site)
                    self.results.setdefault(user_id, []).append((result, datetime.now()))
                    self.save_results(user_id)

    def ping_site(self, site):
        try:
            return site + "/ping"
        except Exception as e:
            return str(e)

    def save_results(self, user_id):
        with open(f"results_{user_id}.txt", "a") as file:
            for result, date in self.results[user_id]:
                file.write(f"{date}: {result}\n")
            self.results[user_id].clear()

    def load_results(self, user_id):
        try:
            with open(f"results_{user_id}.txt", "r") as file:
                lines = file.readlines()
                for line in lines:
                    _, result = line.strip().split(": ")
                    self.results[user_id].append((result, datetime.strptime(line[:19], "%Y-%m-%d %H:%M:%S")))
        except FileNotFoundError:
            pass
```

