Для решения этой задачи можно использовать различные подходы, включая использование векторов для хранения информации о каждом обучающемся и различные алгоритмы для поиска наиболее уникальных или средних обучающихся. Ниже приведен пример реализации программы на C++ для решения данной задачи:

```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

// Функция для сравнения двух обучающихся по возрастанию/убыванию значения параметра
bool compareStudent(const vector<int>& student1, const vector<int>& student2, int param) {
    return student1[param] > student2[param];
}

// Функция для нахождения индексов обучающихся, которые являются уникальными по указанному параметру
vector<int> findUniqueStudents(vector<vector<int>>& matrix, int n, int m, int param) {
    vector<bool> isUnique(n, true);

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (matrix[i][param] == matrix[j][param]) {
                isUnique[j] = false;
                break;
            }
        }
    }

    vector<int> uniqueIndices;
    for (int i = 0; i < n; ++i) {
        if (isUnique[i]) {
            uniqueIndices.push_back(i);
        }
    }

    return uniqueIndices;
}

// Функция для нахождения обучающегося, который является среднем по указанному параметру
int findMedianStudent(vector<vector<int>>& matrix, int n, int m, int param) {
    sort(matrix.begin(), matrix.end(), [param](const vector<int>& a, const vector<int>& b) { return a[param] < b[param]; });

    int medianIndex = n / 2;
    if (n % 2 != 0) {
        // Если количество обучающих нечетно, то медианный элемент будет последним
        return medianIndex;
    } else {
        // Если количество обучающих четно, то медианный элемент будет средним между двумя последними
        return medianIndex - 1;
    }
}

int main() {
    int n, m;
    cout << "Введите количество обучающихся и параметров: ";
    cin >> n >> m;

    vector<vector<int>> matrix(n, vector<int>(m));

    // Заполнение матрицы случайными данными
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            matrix[i][j] = rand() % 100; // Замените rand() на ваш способ генерации данных
        }
    }

    // Находим обучающих, которые являются уникальными по различным параметрам
    vector<int> uniqueByAge = findUniqueStudents(matrix, n, m, 0); // По возрасту
    vector<int> uniqueByHeight = findUniqueStudents(matrix, n, m, 1); // По росту

    // Находим обучающих, которые являются средними по различным параметрам
    int medianByAge = findMedianStudent(matrix, n, m, 0); // По возрасту
    int medianByHeight = findMedianStudent(matrix, n, m, 1); // По росту

    // Выводим результаты
    cout << "Уникальные обучающиеся по возрасту: ";
    for (int i : uniqueByAge) {
        cout << i << " ";
    }
    cout << endl;

    cout << "Средние обучающиеся по возрасту: " << medianByAge << endl;

    cout << "Уникальные обучающиеся по росту: ";
    for (int i : uniqueByHeight) {
        cout << i << " ";
    }
    cout << endl;

    cout << "Средние обучающиеся по росту: " << medianByHeight << endl;

    return 0;
}
```

Этот код демонстрирует базовый подход к решению задачи. Он предполагает, что данные о возрасте и росте каждого обучающегося уже известны. Для других параметров (например, успеваемости) необходимо соответствующим образом адаптировать логику. Также стоит отметить, что для упрощения задачи в этом примере используется случайное заполнение матрицы данными, но в реальных условиях эти данные должны быть получены от пользователя или загружены из файла.

